			return 0.0, fmt.Errorf("failed to set order field %s: %w", key, err)
		}
	}

	// Set order object as a single global variable
	if err := vm.Set("order", orderObj); err != nil {
		return 0.0, fmt.Errorf("failed to set order object: %w", err)
	}

	// Provide safe utility functions
	if err := provideSafeUtilities(vm); err != nil {
		return 0.0, fmt.Errorf("failed to provide utilities: %w", err)
	}

	// Execute the script with error handling
	var result goja.Value
	var err error

	func() {
		defer func() {
			if r := recover(); r != nil {
				err = fmt.Errorf("script panic: %v", r)
			}
		}()
		result, err = vm.RunString(script)
	}()

	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64 with validation
	discount, err := convertToFloat64(result)
	if err != nil {
		return 0.0, err
	}

	// Validate discount value
	if discount < 0 {
		return 0.0, fmt.Errorf("discount cannot be negative: %f", discount)
	}

