// disableDangerousGlobals removes or restricts dangerous JavaScript globals
func disableDangerousGlobals(vm *goja.Runtime) error {
	// Note: goja doesn't expose many Node.js globals by default,
	// but we should still be defensive
	dangerousGlobals := []string{
		"eval",           // Prevent dynamic code evaluation
		"Function",       // Prevent function constructor
		"require",        // Prevent module loading (if available)
		"import",         // Prevent dynamic imports
		"importScripts",  // Prevent script loading
	}

	for _, global := range dangerousGlobals {
		if err := vm.Set(global, goja.Undefined()); err != nil {
			return fmt.Errorf("failed to disable %s: %w", global, err)
		}
	}

	return nil
}

// isValidKey checks if a key name is safe to use
func isValidKey(key string) bool {
	if key == "" || len(key) > 100 {
		return false
	}

	// Prevent keys that might override important properties
	dangerousKeys := map[string]bool{
		"__proto__":     true,
		"constructor":   true,
		"prototype":     true,
		"eval":          true,
		"Function":      true,
		"toString":      true,
		"valueOf":       true,
	}

	return !dangerousKeys[key]
}

// sanitizeValue ensures values are safe for injection
func sanitizeValue(value interface{}) interface{} {
	switch v := value.(type) {
	case string:
		// Limit string length to prevent memory exhaustion
		if len(v) > 10000 {
			return v[:10000]
		}
		return v
	case int, int32, int64, float32, float64, bool:
		return v
	case map[string]interface{}:
		// Recursively sanitize nested maps (with depth limit)
		return sanitizeMap(v, 0, 5)
	case []interface{}:
		// Sanitize arrays (with size limit)
		return sanitizeArray(v, 0, 5)
	default:
		// Convert unknown types to string representation
		return fmt.Sprintf("%v", v)
	}
}

// sanitizeMap recursively sanitizes map values with depth limit
func sanitizeMap(m map[string]interface{}, depth, maxDepth int) map[string]interface{} {
	if depth >= maxDepth {
		return map[string]interface{}{"error": "max depth exceeded"}
	}

	result := make(map[string]interface{})
	count := 0
	maxItems := 100

	for k, v := range m {
		if count >= maxItems {
			break
		}
		if isValidKey(k) {
			result[k] = sanitizeValue(v)
			count++
		}
	}
	return result
}

// sanitizeArray sanitizes array values with size limit
func sanitizeArray(arr []interface{}, depth, maxDepth int) []interface{} {
	if depth >= maxDepth {
		return []interface{}{"error: max depth exceeded"}
	}

	maxSize := 1000
	size := len(arr)
	if size > maxSize {
		size = maxSize
	}

	result := make([]interface{}, size)
	for i := 0; i < size; i++ {
		result[i] = sanitizeValue(arr[i])
	}
	return result
}

// provideSafeUtilities adds safe utility functions to the VM
func provideSafeUtilities(vm *goja.Runtime) error {
	// Provide Math functions (already safe in goja)
	// Provide safe console.log for debugging (optional, can be removed in production)
	console := vm.NewObject()
	console.Set("log", func(args ...interface{}) {
		// In production, you might want to disable this or log to a secure location
		// For now, we'll keep it but limit output
		if len(args) > 10 {
			args = args[:10]
		}
		output := fmt.Sprint(args...)
		fmt.Println("[Script]:", output)
	})

	return vm.Set("console", console)
}

// convertToFloat64 safely converts a Goja value to float64
func convertToFloat64(result goja.Value) (float64, error) {
	if result == nil || goja.IsUndefined(result) || goja.IsNull(result) {
		return 0.0, fmt.Errorf("script returned null or undefined")
	}

	exported := result.Export()

	switch v := exported.(type) {
	case float64:
		return v, nil
	case int:
		return float64(v), nil
	case int32:
		return float64(v), nil
	case int64:
		return float64(v), nil
	case float32:
		return float64(v), nil
	case uint:
		return float64(v), nil
	case uint32:
		return float64(v), nil
	case uint64:
		return float64(v), nil
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", exported)
	}
}

