// sanitizeMap recursively sanitizes nested maps with depth limit
func sanitizeMap(m map[string]interface{}, currentDepth, maxDepth int) map[string]interface{} {
	if currentDepth > maxDepth {
		return make(map[string]interface{})
	}

	sanitized := make(map[string]interface{})
	for key, value := range m {
		if key == "" {
			continue
		}
		switch v := value.(type) {
		case string, int, int32, int64, float32, float64, bool, nil:
			sanitized[key] = v
		case map[string]interface{}:
			sanitized[key] = sanitizeMap(v, currentDepth+1, maxDepth)
		default:
			// Skip complex types
			continue
		}
	}
	return sanitized
}

// convertToFloat64 safely converts a Goja value to float64
func convertToFloat64(value goja.Value) (float64, error) {
	if value == nil || goja.IsUndefined(value) || goja.IsNull(value) {
		return 0.0, fmt.Errorf("script returned null or undefined")
	}

	exported := value.Export()

	switch v := exported.(type) {
	case float64:
		return v, nil
	case float32:
		return float64(v), nil
	case int:
		return float64(v), nil
	case int32:
		return float64(v), nil
	case int64:
		return float64(v), nil
	case uint:
		return float64(v), nil
	case uint32:
		return float64(v), nil
	case uint64:
		return float64(v), nil
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", exported)
	}
}

